const INTERCEPT = [0.02168675553764884, -0.040387916166084815, 0.01870116062837377];
const EPS = 1e-6;

function dot(a, b) {
  let s = 0.0;
  for (let i = 0; i < a.length; i++) s += a[i] * b[i];
  return s;
}

function hypot2(x, y) {
  return Math.hypot(x, y);
}

function subtract(a, b) {
  return [a[0] - b[0], a[1] - b[1]];
}

function meanPoints(points) {
  if (!points.length) return null;
  let sx = 0.0, sy = 0.0;
  for (const p of points) {
    sx += p[0];
    sy += p[1];
  }
  return [sx / points.length, sy / points.length];
}

function softmax(logits) {
  let maxLogit = -Infinity;
  for (const v of logits) if (v > maxLogit) maxLogit = v;
  const exps = new Array(logits.length);
  let sum = 0.0;
  for (let i = 0; i < logits.length; i++) {
    const e = Math.exp(logits[i] - maxLogit);
    exps[i] = e;
    sum += e;
  }
  for (let i = 0; i < exps.length; i++) exps[i] /= sum;
  return exps;
}

function angleTriplet(a, b, c) {
  if (!a || !b || !c) return null;
  const v1 = [a[0] - b[0], a[1] - b[1]];
  const v2 = [c[0] - b[0], c[1] - b[1]];
  const n1 = Math.hypot(v1[0], v1[1]);
  const n2 = Math.hypot(v2[0], v2[1]);
  if (n1 < EPS || n2 < EPS) return null;
  let cosang = (v1[0] * v2[0] + v1[1] * v2[1]) / (n1 * n2);
  cosang = Math.max(-1, Math.min(1, cosang));
  return Math.acos(cosang);
}

function safeDistance(a, b) {
  if (!a || !b) return null;
  return Math.hypot(a[0] - b[0], a[1] - b[1]);
}

export function createRelativePoseFeatures(keypoints) {
  if (!Array.isArray(keypoints) || keypoints.length !== 48) {
    throw new Error("Expected 48 values: [x1, y1, ..., x24, y24].");
  }

  const pts = new Array(24);
  const visible = new Array(24);

  for (let i = 0; i < 24; i++) {
    const x = Number(keypoints[2 * i]);
    const y = Number(keypoints[2 * i + 1]);
    const ok = Number.isFinite(x) && Number.isFinite(y);
    pts[i] = ok ? [x, y] : null;
    visible[i] = ok ? 1.0 : 0.0;
  }

  const get = (idx1) => pts[idx1 - 1];
  const meanOf = (indices) => meanPoints(indices.map(get).filter(Boolean));

  let chest = meanOf([9, 11, 3, 21, 23, 24]);
  if (!chest) chest = meanOf([9, 11, 3]);

  const leftBody = meanOf([12, 9, 10, 16, 20]);
  const rightBody = meanOf([6, 3, 2, 5, 15, 19]);

  const visiblePoints = pts.filter(Boolean);
  const origin = chest || meanPoints(visiblePoints) || [0.0, 0.0];

  let ex;
  if (leftBody && rightBody) ex = subtract(rightBody, leftBody);
  else if (get(12) && get(6)) ex = subtract(get(6), get(12));
  else if (get(9) && get(3)) ex = subtract(get(3), get(9));
  else ex = [1.0, 0.0];

  let exNorm = Math.hypot(ex[0], ex[1]);
  if (exNorm < EPS) {
    ex = [1.0, 0.0];
    exNorm = 1.0;
  }
  ex = [ex[0] / exNorm, ex[1] / exNorm];
  const ey = [-ex[1], ex[0]];

  const scaleCandidates = [
    safeDistance(get(12), get(6)),
    safeDistance(get(9), get(3)),
    safeDistance(get(10), get(2)),
    safeDistance(get(20), get(19)),
    safeDistance(get(15), get(16)),
  ].filter((v) => v !== null && v > EPS);

  let scale = 1.0;
  if (scaleCandidates.length) {
    scaleCandidates.sort((a, b) => a - b);
    scale = scaleCandidates[(scaleCandidates.length / 2) | 0];
  }

  const uv = {};
  const features = [];

  for (let i = 0; i < 24; i++) features.push(visible[i]);

  for (let i = 1; i <= 24; i++) {
    const p = get(i);
    if (!p) {
      uv[i] = null;
      features.push(0.0, 0.0);
      continue;
    }
    const dx = (p[0] - origin[0]) / scale;
    const dy = (p[1] - origin[1]) / scale;
    const u = dx * ex[0] + dy * ex[1];
    const v = dx * ey[0] + dy * ey[1];
    uv[i] = [u, v];
    features.push(u, v);
  }

  const visUv = Object.values(uv).filter(Boolean);
  let uExtent = 0.0;
  let vExtent = 0.0;
  if (visUv.length >= 2) {
    let uMin = Infinity, uMax = -Infinity, vMin = Infinity, vMax = -Infinity;
    for (const [u, v] of visUv) {
      if (u < uMin) uMin = u;
      if (u > uMax) uMax = u;
      if (v < vMin) vMin = v;
      if (v > vMax) vMax = v;
    }
    uExtent = uMax - uMin;
    vExtent = vMax - vMin;
  }
  features.push(uExtent, vExtent, uExtent / Math.max(vExtent, EPS), vExtent / Math.max(uExtent, EPS));

  const distancePairs = [[1,7],[1,11],[1,21],[7,11],[7,21],[11,21],[3,9],[6,12],[2,10],[15,16],[19,20],[14,17],[13,18],[21,24],[22,23]];
  for (const [a, b] of distancePairs) {
    const pa = uv[a], pb = uv[b];
    features.push((!pa || !pb) ? 0.0 : hypot2(pb[0] - pa[0], pb[1] - pa[1]));
  }

  const offsetPairs = [[11,7],[11,1],[21,7],[21,1],[17,11],[17,21],[18,11],[4,11],[13,17],[14,17]];
  for (const [a, b] of offsetPairs) {
    const pa = uv[a], pb = uv[b];
    if (!pa || !pb) features.push(0.0, 0.0);
    else features.push(pb[0] - pa[0], pb[1] - pa[1]);
  }

  const angleTriplets = [[10,8,7],[3,2,1],[20,17,19],[16,17,15],[11,21,17],[9,11,3],[12,21,6],[21,23,24]];
  for (const [a, b, c] of angleTriplets) {
    const ang = angleTriplet(get(a), get(b), get(c));
    if (ang === null) features.push(0.0, 0.0);
    else features.push(Math.sin(ang), Math.cos(ang));
  }

  return features;
}

export function classifyRelativePoseFeatures(features) {
  if (!Array.isArray(features) || features.length !== COEF[0].length) {
    throw new Error(`Expected ${COEF[0].length} features, got ${features?.length ?? "unknown"}.`);
  }

  const logits = new Array(CLASS_NAMES.length);
  for (let c = 0; c < CLASS_NAMES.length; c++) {
    let s = INTERCEPT[c];
    const w = COEF[c];
    for (let i = 0; i < features.length; i++) {
      s += w[i] * features[i];
    }
    logits[c] = s;
  }

  const probs = softmax(logits);
  let bestIdx = 0;
  for (let i = 1; i < probs.length; i++) {
    if (probs[i] > probs[bestIdx]) bestIdx = i;
  }

  return {
    label: CLASS_NAMES[bestIdx],
    probabilities: {
      lie: probs[CLASS_NAMES.indexOf("lie")] ?? 0,
      sit: probs[CLASS_NAMES.indexOf("sit")] ?? 0,
      stand: probs[CLASS_NAMES.indexOf("stand")] ?? 0,
    },
    logits,
  };
}

